mapper.insert:
insert into qa_session (
    project_id, title, status, created_at, updated_at, created_by, updated_by
) values (
    #{projectId}, #{title}, #{status}, now(), now(), #{createdBy}, #{updatedBy}
)

mapper.select:
select id, project_id, session_id, user_id, role, content, reply_status, route_mode,
       route_rationale, answer_content, pending_reason, clarification_question,
       request_id, created_at, created_by, updated_by
from qa_message
where project_id = #{projectId}
  and session_id = #{sessionId}
  and deleted = 0
order by id desc
limit #{limit}

mapper.insert:
insert into qa_message (
    project_id, session_id, user_id, role, content, reply_status, route_mode,
    route_rationale, answer_content, pending_reason, clarification_question,
    request_id, created_at, updated_at, created_by, updated_by
) values (
    #{projectId}, #{sessionId}, #{userId}, #{role}, #{content}, #{replyStatus}, #{routeMode},
    #{routeRationale}, #{answerContent}, #{pendingReason}, #{clarificationQuestion},
    #{requestId}, now(), now(), #{createdBy}, #{updatedBy}
)
